import { useEffect, useMemo, useState } from "react";
import {
  ArrowUpRight,
  BadgeCheck,
  Droplets,
  Eye,
  Filter,
  Leaf,
  Lock,
  LogOut,
  Mail,
  MapPin,
  PenLine,
  Phone,
  Search,
  Sparkles,
  Sprout,
  Star,
  SunMedium,
  Trash2
} from "lucide-react";
import { api } from "./api";
import logo from "./assets/modern-nature-logo.jpg";

const emptyForm = {
  name: "",
  category: "",
  priceText: "",
  description: "",
  careLevel: "Easy",
  light: "",
  imageUrl: "",
  featured: false,
  inStock: true
};

const fallbackProducts = [
  {
    _id: "sample-1",
    name: "Monstera Deliciosa",
    category: "Indoor Statement Plant",
    priceText: "From Rs. 4,500",
    description: "Broad split leaves with a bold tropical shape, perfect for living rooms, lobbies, and sunlit corners.",
    careLevel: "Easy",
    light: "Bright filtered light",
    imageUrl: "https://images.unsplash.com/photo-1614594975525-e45190c55d0b?auto=format&fit=crop&w=1200&q=85",
    featured: true,
    inStock: true
  },
  {
    _id: "sample-2",
    name: "Fiddle Leaf Fig",
    category: "Premium Indoor Plant",
    priceText: "From Rs. 6,800",
    description: "Glossy violin-shaped leaves that bring instant height and elegance to modern interiors.",
    careLevel: "Moderate",
    light: "Bright indirect light",
    imageUrl: "https://images.unsplash.com/photo-1597055181300-e3633a207c8a?auto=format&fit=crop&w=1200&q=85",
    featured: true,
    inStock: true
  },
  {
    _id: "sample-3",
    name: "Snake Plant",
    category: "Low Maintenance Plant",
    priceText: "From Rs. 2,200",
    description: "Architectural upright leaves, excellent resilience, and a clean modern look.",
    careLevel: "Easy",
    light: "Low to bright indirect light",
    imageUrl: "https://images.unsplash.com/photo-1593482892290-f54927ae2b7d?auto=format&fit=crop&w=1200&q=85",
    featured: false,
    inStock: true
  }
];

function App() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [query, setQuery] = useState("");
  const [category, setCategory] = useState("All");
  const [route, setRoute] = useState(window.location.pathname);
  const [token, setToken] = useState(localStorage.getItem("mnp_token") || "");

  const loadProducts = async () => {
    setLoading(true);
    try {
      const data = await api.getProducts();
      setProducts(data);
    } catch (error) {
      setProducts(fallbackProducts);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadProducts();
  }, []);

  useEffect(() => {
    const onPop = () => setRoute(window.location.pathname);
    window.addEventListener("popstate", onPop);
    return () => window.removeEventListener("popstate", onPop);
  }, []);

  const navigate = (path) => {
    window.history.pushState({}, "", path);
    setRoute(path);
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const categories = useMemo(() => ["All", ...new Set(products.map((product) => product.category))], [products]);
  const filteredProducts = useMemo(() => {
    return products.filter((product) => {
      const matchesSearch = `${product.name} ${product.category} ${product.description}`.toLowerCase().includes(query.toLowerCase());
      const matchesCategory = category === "All" || product.category === category;
      return matchesSearch && matchesCategory;
    });
  }, [products, query, category]);
  const featuredProducts = useMemo(() => products.filter((product) => product.featured), [products]);

  if (route === "/admin") {
    return (
      <AdminDashboard
        token={token}
        setToken={setToken}
        products={products}
        reload={loadProducts}
        navigate={navigate}
      />
    );
  }

  return (
    <main>
      <Header navigate={navigate} />
      <Hero />
      <ProductShowcase
        products={filteredProducts}
        categories={categories}
        category={category}
        setCategory={setCategory}
        query={query}
        setQuery={setQuery}
        loading={loading}
      />
      <FeaturedStrip products={featuredProducts.length ? featuredProducts : products.slice(0, 3)} />
      <About />
      <Contact />
      <Footer navigate={navigate} />
    </main>
  );
}

function Header({ navigate }) {
  return (
    <header className="site-header" id="home">
      <button className="brand" onClick={() => navigate("/")} aria-label="Modern Nature Plant home">
        <span className="brand-mark logo-mark"><img src={logo} alt="" /></span>
        <span>Modern Nature Plant</span>
      </button>
      <nav>
        <a href="#home">Home</a>
        <a href="#collection">Plants</a>
        <a href="#about">About</a>
        <a href="#contact">Contact</a>
      </nav>
    </header>
  );
}

function Hero() {
  return (
    <section className="hero">
      <div className="hero-panel">
        <div className="hero-copy">
          <p className="eyebrow"><Sparkles size={16} /> Plants for a better life</p>
          <h1>Modern Nature Plant</h1>
          <p>
            Fresh indoor and outdoor plants displayed beautifully for homes,
            offices, cafes, and thoughtful green gifts.
          </p>
          <div className="hero-actions">
            <a className="primary-action" href="#collection">
              Browse plants <ArrowUpRight size={18} />
            </a>
            <a className="secondary-action" href="#contact">
              Contact us
            </a>
          </div>
        </div>
        <div className="hero-gallery" aria-label="Plant showroom photos">
          <img
            className="hero-gallery-main"
            src="https://images.unsplash.com/photo-1521334884684-d80222895322?auto=format&fit=crop&w=1400&q=90"
            alt="Indoor plants near a bright wall"
          />
          <img
            className="hero-gallery-small top"
            src="https://images.unsplash.com/photo-1614594975525-e45190c55d0b?auto=format&fit=crop&w=900&q=90"
            alt="Monstera plant leaves"
          />
          <img
            className="hero-gallery-small bottom"
            src="https://images.unsplash.com/photo-1593482892290-f54927ae2b7d?auto=format&fit=crop&w=900&q=90"
            alt="Snake plant in a pot"
          />
        </div>
      </div>
    </section>
  );
}

function About() {
  return (
    <section className="about-section" id="about">
      <div className="hero-content">
        <p className="eyebrow"><Eye size={16} /> About us</p>
        <h2>We help every space feel calmer, fresher, and more alive.</h2>
        <p>
          Modern Nature Plant is a display-first plant business. Customers can
          explore our collection, see care details, and contact us directly for
          availability, pricing, and plant selection help.
        </p>
        <div className="about-points">
          <span><BadgeCheck size={18} /> Healthy selected greenery</span>
          <span><BadgeCheck size={18} /> Indoor and outdoor plant options</span>
          <span><BadgeCheck size={18} /> Direct support before purchase</span>
        </div>
      </div>
      <div className="about-image" />
    </section>
  );
}

function PlantHighlights() {
  return (
    <section className="trust-bar" aria-label="Shop highlights">
      <div><Sprout size={22} /><span>Healthy selected plants</span></div>
      <div><Leaf size={22} /><span>Indoor and outdoor greenery</span></div>
      <div><Droplets size={22} /><span>Care details included</span></div>
      <div><BadgeCheck size={22} /><span>Display-only browsing</span></div>
    </section>
  );
}

function ProductShowcase({ products, categories, category, setCategory, query, setQuery, loading }) {
  return (
    <section className="section collection" id="collection">
      <div className="section-heading">
        <div>
          <p className="eyebrow"><Leaf size={16} /> Our plants</p>
          <h2>Choose a plant that fits your space.</h2>
        </div>
        <p className="section-note">
          Browse our plants, check care needs, and contact us directly for current availability.
        </p>
      </div>

      <PlantHighlights />

      <div className="catalog-tools">
        <label className="search-box">
          <Search size={18} />
          <input
            value={query}
            onChange={(event) => setQuery(event.target.value)}
            placeholder="Search by plant, type, or care"
          />
        </label>
        <div className="filter-label"><Filter size={17} /> Filter</div>
        <div className="category-row">
          {categories.map((item) => (
            <button
              key={item}
              className={item === category ? "active" : ""}
              onClick={() => setCategory(item)}
            >
              {item}
            </button>
          ))}
        </div>
      </div>

      {loading ? (
        <div className="status-panel">Loading plants...</div>
      ) : products.length ? (
        <div className="product-grid">
          {products.map((product) => (
            <ProductCard key={product._id} product={product} />
          ))}
        </div>
      ) : (
        <div className="status-panel">
          <strong>No plants found.</strong>
          <span>Try another category or search word.</span>
        </div>
      )}
    </section>
  );
}

function FeaturedStrip({ products }) {
  if (!products.length) return null;

  return (
    <section className="featured-strip" aria-label="Featured plants">
      <div className="featured-copy">
        <p className="eyebrow"><Star size={16} /> Featured picks</p>
        <h2>Popular plants for modern rooms.</h2>
      </div>
      <div className="featured-list">
        {products.slice(0, 3).map((product) => (
          <article key={product._id} className="featured-mini">
            <img src={product.imageUrl} alt={product.name} />
            <div>
              <strong>{product.name}</strong>
              <span>{product.priceText || "Contact for price"}</span>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
}

function ProductCard({ product }) {
  return (
    <article className="product-card">
      <div className="product-image">
        <img src={product.imageUrl} alt={product.name} />
        {product.featured && <span className="floating-tag">Featured</span>}
      </div>
      <div className="product-body">
        <div>
          <p className="product-category">{product.category}</p>
          <h3>{product.name}</h3>
        </div>
        <p>{product.description}</p>
        <div className="plant-meta">
          <span><SunMedium size={16} /> {product.light}</span>
          <span><Droplets size={16} /> {product.careLevel}</span>
        </div>
        <div className="product-footer">
          <strong>{product.priceText || "Contact for price"}</strong>
          <span className={product.inStock ? "stock in" : "stock out"}>
            {product.inStock ? "Available" : "Ask first"}
          </span>
        </div>
      </div>
    </article>
  );
}

function Contact() {
  return (
    <section className="contact" id="contact">
      <div>
        <p className="eyebrow"><Mail size={16} /> Get in touch</p>
        <h2>Ready to bring fresh green life into your space?</h2>
        <p>Call, email, or message Modern Nature Plant to check availability and arrange your plants.</p>
      </div>
      <div className="contact-actions">
        <a href="tel:+94771234567"><Phone size={18} /> Call +94 77 123 4567</a>
        <a href="mailto:hello@modernnatureplant.com"><Mail size={18} /> hello@modernnatureplant.com</a>
        <a href="https://wa.me/94771234567"><MapPin size={18} /> WhatsApp inquiry</a>
      </div>
    </section>
  );
}

function Footer({ navigate }) {
  return (
    <footer>
      <div className="brand">
        <span className="brand-mark logo-mark"><img src={logo} alt="" /></span>
        <span>Modern Nature Plant</span>
      </div>
      <span className="footer-note">Premium plant display catalog</span>
      <button onClick={() => navigate("/admin")}>Admin</button>
    </footer>
  );
}

function AdminDashboard({ token, setToken, products, reload, navigate }) {
  const [loginForm, setLoginForm] = useState({ email: "", password: "" });
  const [form, setForm] = useState(emptyForm);
  const [editingId, setEditingId] = useState("");
  const [message, setMessage] = useState("");
  const [uploading, setUploading] = useState(false);

  const login = async (event) => {
    event.preventDefault();
    setMessage("");
    try {
      const data = await api.login(loginForm);
      localStorage.setItem("mnp_token", data.token);
      setToken(data.token);
      setMessage("Welcome back, admin.");
    } catch (error) {
      setMessage(error.message);
    }
  };

  const logout = () => {
    localStorage.removeItem("mnp_token");
    setToken("");
  };

  const saveProduct = async (event) => {
    event.preventDefault();
    setMessage("");
    try {
      if (editingId) {
        await api.updateProduct(editingId, form, token);
        setMessage("Product updated.");
      } else {
        await api.createProduct(form, token);
        setMessage("Product added.");
      }
      setForm(emptyForm);
      setEditingId("");
      await reload();
    } catch (error) {
      setMessage(error.message);
    }
  };

  const uploadImage = async (event) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setUploading(true);
    setMessage("");
    try {
      const data = await api.uploadImage(file, token);
      setForm((current) => ({ ...current, imageUrl: data.imageUrl }));
      setMessage("Image uploaded.");
    } catch (error) {
      setMessage(error.message);
    } finally {
      setUploading(false);
      event.target.value = "";
    }
  };

  const editProduct = (product) => {
    setEditingId(product._id);
    setForm({
      name: product.name || "",
      category: product.category || "",
      priceText: product.priceText || "",
      description: product.description || "",
      careLevel: product.careLevel || "Easy",
      light: product.light || "",
      imageUrl: product.imageUrl || "",
      featured: Boolean(product.featured),
      inStock: Boolean(product.inStock)
    });
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const deleteProduct = async (id) => {
    const confirmed = window.confirm("Delete this product?");
    if (!confirmed) return;
    try {
      await api.deleteProduct(id, token);
      await reload();
      setMessage("Product deleted.");
    } catch (error) {
      setMessage(error.message);
    }
  };

  if (!token) {
    return (
      <main className="admin-page">
        <button className="back-button" onClick={() => navigate("/")}>Back to website</button>
        <section className="login-panel">
          <div>
            <img className="admin-login-logo" src={logo} alt="Modern Nature Plant logo" />
            <p className="eyebrow"><Lock size={16} /> Admin access</p>
            <h1>Modern Nature Plant</h1>
            <p>Sign in to add, edit, feature, or hide products in the display catalog.</p>
          </div>
          <form onSubmit={login}>
            <input
              type="email"
              placeholder="Admin email"
              value={loginForm.email}
              onChange={(event) => setLoginForm({ ...loginForm, email: event.target.value })}
              required
            />
            <input
              type="password"
              placeholder="Password"
              value={loginForm.password}
              onChange={(event) => setLoginForm({ ...loginForm, password: event.target.value })}
              required
            />
            <button type="submit">Login</button>
            {message && <p className="form-message">{message}</p>}
          </form>
        </section>
      </main>
    );
  }

  return (
    <main className="admin-page">
      <div className="admin-topbar">
        <button className="back-button" onClick={() => navigate("/")}>Back to website</button>
        <button className="logout-button" onClick={logout}><LogOut size={17} /> Logout</button>
      </div>

      <section className="admin-layout">
        <form className="product-form" onSubmit={saveProduct}>
          <p className="eyebrow"><PenLine size={16} /> Product manager</p>
          <h1>{editingId ? "Edit plant" : "Add a plant"}</h1>
          <input placeholder="Plant name" value={form.name} onChange={(event) => setForm({ ...form, name: event.target.value })} required />
          <input placeholder="Category" value={form.category} onChange={(event) => setForm({ ...form, category: event.target.value })} required />
          <input placeholder="Price text" value={form.priceText} onChange={(event) => setForm({ ...form, priceText: event.target.value })} />
          <input placeholder="Light needs" value={form.light} onChange={(event) => setForm({ ...form, light: event.target.value })} />
          <label className="upload-box">
            <span>{uploading ? "Uploading image..." : "Upload plant image"}</span>
            <input type="file" accept="image/*" onChange={uploadImage} disabled={uploading} />
          </label>
          {form.imageUrl && (
            <div className="image-preview">
              <img src={form.imageUrl} alt="Selected plant preview" />
              <span>Image ready</span>
            </div>
          )}
          <input placeholder="Image URL" value={form.imageUrl} onChange={(event) => setForm({ ...form, imageUrl: event.target.value })} required />
          <select value={form.careLevel} onChange={(event) => setForm({ ...form, careLevel: event.target.value })}>
            <option>Easy</option>
            <option>Moderate</option>
            <option>Expert</option>
          </select>
          <textarea placeholder="Description" value={form.description} onChange={(event) => setForm({ ...form, description: event.target.value })} required />
          <label className="check-row">
            <input type="checkbox" checked={form.featured} onChange={(event) => setForm({ ...form, featured: event.target.checked })} />
            Featured product
          </label>
          <label className="check-row">
            <input type="checkbox" checked={form.inStock} onChange={(event) => setForm({ ...form, inStock: event.target.checked })} />
            Available
          </label>
          <button type="submit">{editingId ? "Save changes" : "Add product"}</button>
          {editingId && <button type="button" className="ghost-button" onClick={() => { setEditingId(""); setForm(emptyForm); }}>Cancel edit</button>}
          {message && <p className="form-message">{message}</p>}
        </form>

        <div className="admin-products">
          <div className="admin-heading">
            <h2>Current catalog</h2>
            <span>{products.length} plants</span>
          </div>
          {products.map((product) => (
            <article key={product._id} className="admin-product">
              <img src={product.imageUrl} alt={product.name} />
              <div>
                <strong>{product.name}</strong>
                <span>{product.category}</span>
              </div>
              <button onClick={() => editProduct(product)} aria-label={`Edit ${product.name}`}><PenLine size={17} /></button>
              <button onClick={() => deleteProduct(product._id)} aria-label={`Delete ${product.name}`}><Trash2 size={17} /></button>
            </article>
          ))}
        </div>
      </section>
    </main>
  );
}

export default App;
